
public class ejercicio9 {

	public static void main(String[] args) {
		// TODO Auto-generated method stub

		int minutos = 95745687; 
		int años ; 
		int dias ; 
		int minutosEnAno = 60 * 24 * 365;
		años = (minutos / minutosEnAno); 
		dias = ((minutos / 60/24) / 365); 
		System.out.println("Los minutos en años son "+ años);
		System.out.println("Los minutos en dias son "+ dias);
		
		
		
		
		
		
		
		
		
		
		
		
	}

}
